    const n = nums.length;
    let goodSubarrayCount = 0;

    // Iterate over all possible starting indices i
    for (let i = 0; i < n; i++) {
        let currentOr = 0;
        // Keep track of which numbers are present in the current subarray [i...j]
        // Since the maximum value is 10^9, we can't use a simple boolean array for presence.
        // We need to check if the bitwise OR of the subarray equals one of its elements.

        // We use a Set to store the elements of the current subarray for O(1) lookups.
        const presentElements = new Set();

        // Iterate over all possible ending indices j (j >= i)
        for (let j = i; j < n; j++) {
            const numJ = nums[j];

            // Update the running bitwise OR for the subarray nums[i...j]
            currentOr |= numJ;

            // Add the new element to the set of present elements
            presentElements.add(numJ);

            // Check the condition: 
            // "the bitwise OR of all elements equals at least one element present in the subarray"
            // This means currentOr must be equal to some element x in presentElements.
            let isGood = false;
            for (const element of presentElements) {
                if (currentOr === element) {
                    isGood = true;
                    break;
